#include<bits/stdc++.h>
using namespace std;
int n,m,v[310],w[310];
long long f[10010];
bool check(int mid)
{
    memset(f,-0x3f,sizeof(f));
    f[0]=0;
    long long inf=f[1];
    for(int i=1;i<=n;i++)
    {
        for(int j=m;j>=0;j--)
        {
            if(f[j]!=inf)
            {
                long long k=min(m,j+w[i]);
                f[k]=max(f[k],f[j]+v[i]-1ll*w[i]*mid);
            }
        }
    }
    return f[m]>=0;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&w[i],&v[i]);
        v[i]*=1000;
    }
    int l=0,r=1e9,best;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            l=mid+1;
            best=mid;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%d",best);
    return 0;
}
